class Solution {
public:
    bool solve(vector<int>& nums) {
        for (int i = 0; i < nums.size() - 1; ++i)
            for (int j = nums.size() - 1; j > i; --j)
                if (nums[j] < nums[i])
                    swap(nums[i], nums[j]);
        return nums == sorted(nums);
    }
};

